struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using stream's operator<<
        stream << packet_id;

        // Write username with prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count + scores using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer (std::vector<uint8_t>)
    std::vector<uint8_t> buffer;

    // Create a stream using the buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Call the serialise method on the packet object, passing the stream as an argument
    packet.serialise(stream);

    // Return the populated buffer
    return buffer;
}
```

