#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // 1. Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // 2. Use buffer_adaptor's preview function to get the first byte (data_type)
    uint8_t data_type = 0;
    if (adaptor.size() >= 1) {
        auto preview_span = adaptor.preview<uint8_t>(1);
        if (!preview_span.empty()) {
            data_type = preview_span[0];
        }
    }

    // 3. Check the available data size using buffer_adaptor's size function
    const auto total_size = adaptor.size();

    // 4. Calculate the expected item count based on available size
    // Header: 1 byte (data_type) + 4 bytes (item_count) = 5 bytes
    // Each item is 4 bytes (uint32_t or float)
    uint32_t item_count = 0;
    if (total_size > 5) {
        item_count = (total_size - 5) / 4;
    }

    // 5. Create a binary_stream from the buffer_adaptor
    hexi::binary_stream<hexi::buffer_adaptor<std::span<const uint8_t>>> stream(adaptor);

    // 6. Read the item_count from the binary_stream
    uint32_t read_item_count = 0;
    stream >> read_item_count;

    // Verify item count matches expectation
    if (read_item_count != item_count) {
        return {data_type, {}, {}};
    }

    // 7. Based on data_type, read either uint32_t or float items into vectors
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;

    if (data_type == 0) { // Integers
        int_items.resize(read_item_count);
        for (uint32_t i = 0; i < read_item_count; ++i) {
            uint32_t value;
            stream >> value;
            int_items[i] = value;
