        float_items.resize(read_item_count);
        for (uint32_t i = 0; i < read_item_count; ++i) {
            float value;
            stream >> value;
            float_items[i] = value;
        }
    }

    // 8. Return a DataResult struct with the data_type and appropriate vector
    return {data_type, int_items, float_items};
}
