Based on the reference materials and detailed specifications, here's the complete implementation of the required functions:

```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    std::vector<uint8_t> data(bytes_to_read);
    std::size_t bytes_read = buffer.read(data.data(), bytes_to_read);

    if (bytes_read < bytes_to_read && buffer.error()) {
        throw std::runtime_error("Error reading file: " + file_path.string());
    }

    data.resize(bytes_read);
    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    std::vector<uint8_t> data(bytes_to_preview);
    std::size_t bytes_copied = buffer.copy(data.data(), bytes_to_preview);

    if (bytes_copied < bytes_to_preview && buffer.error()) {
        throw std::runtime_error("Error previewing file: " + file_path.string());
    }

    data.resize(bytes_copied);
    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    std::size_t bytes_written = buffer.write(data.data(), data.size());

    if (bytes_written < data.size() && buffer.error()) {
        throw std::runtime_error("Error writing to file: " + file_path.string());
    }
}

