#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    return varint_encode<std::uint64_t, hexi::pmc::binary_stream_writer>(writer, value);
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    return varint_decode<std::uint64_t, hexi::pmc::binary_stream_reader>(reader);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;

    // Create a buffer adaptor for the vector
    hexi::pmc::buffer_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Create binary stream writer and reader using the adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the value
    std::size_t bytes_written = encode_varint(writer, original_value);

    // Reset the reader position to start of buffer
    // Note: In a real implementation, you'd need to seek to the beginning
    // For simplicity, we'll create a new reader on the same buffer
    hexi::pmc::binary_stream_reader new_reader(adaptor);

    // Decode the value
    T decoded_value = decode_varint(new_reader);

    // Compare with original value
    return decoded_value == original_value;
}
```

