std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to hold the written data
    std::vector<std::uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<std::uint8_t>> adaptor(buffer);

    // Calculate total size to be written
    std::size_t total_size = 0;
    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Write each chunk with size checking
    for (const auto& chunk : chunks) {
        // Check available free space before each write
        std::size_t available_space = adaptor.free();

        // If chunk is larger than available space, adjust to available space
        std::size_t write_size = chunk.size();
        if (write_size > available_space) {
            write_size = available_space;
        }

        // Write the chunk
        adaptor.write(chunk.data(), write_size);
    }

    // Return the total size written (should match buffer size)
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<const std::vector<std::uint8_t>> adaptor(buffer);

    std::vector<uint8_t> result;
    std::size_t remaining = adaptor.size();

    // Read until buffer is empty
    while (remaining > 0) {
        // Calculate read size (min of chunk_size and remaining data)
        std::size_t read_size = (chunk_size < remaining) ? chunk_size : remaining;

        // Create destination buffer for read operation
        std::vector<uint8_t> temp(read_size);

        // Perform read operation
        adaptor.read(temp.data(), read_size);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());

        // Update remaining data
        remaining = adaptor.size();
    }

    return result;
}
