#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write temperatures
        for (const auto& temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(temp);
            adaptor.write(converted);
        }

        // Convert and write pressure
        auto converted_pressure = hexi::endian::conditional_reverse<std::endian::native, std::endian::little>(pressure);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(&sensor_id);

        // Read and convert temperatures
        for (auto& temp : temperatures) {
            float read_temp;
            adaptor.read(&read_temp);
            hexi::endian::little_to_native_inplace(read_temp);
            temp = read_temp;
        }

        // Read and convert pressure
        double read_pressure;
        adaptor.read(&read_pressure);
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    hexi::buffer_adaptor<std::vector<uint8_t>> buffer;
    hexi::stream stream(buffer);
    data.serialise(stream);
    return buffer.data();
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);
    hexi::stream stream(adaptor);
    MeasurementData data;
    data.deserialise(stream);
    return data;
}

